            if (dx === 0 && dy === 0) continue;

            const g = gcd(Math.abs(dx), Math.abs(dy));
            dx /= g;
            dy /= g;
            if (dx < 0 || (dx === 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            const key = `${dx},${dy}`;
            slopeCounts.set(key, (slopeCounts.get(key) || 0) + 1);
        }

        for (const cnt of slopeCounts.values()) {
