            if (dx < 0 || (dx === 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            const key = `${dx},${dy}`;
            if (!lineMap.has(key)) {
                lineMap.set(key, new Set());
            }
            lineMap.get(key).add(i);
            lineMap.get(key).add(j);
        }
    }

    let parallelogram = 0;
    for (const s of lineMap.values()) {
        const m = s.size;
        if (m >= 4) {
            parallelogram += m * (m - 1) * (m - 2) * (m - 3) / 24;
        }
    }

    res = res - 3 * parallelogram;
    res = Math.floor(res / 2);

    return res;
}
